241	    } // class
242	
243	    // commit the local write pointer back once per anchor
244	    total_boxes = tb;
245	
246	    // // For each class produce a box (same as CPU code)
247	    // CLASS_EMIT_LOOP:
248	    // for (int m = 0; m < NUM_CLASSES; ++m) {
249	    // //		#pragma HLS UNROLL
250	
251	    //     int idx = n * OUTPUT_DIM + 64 + m;
