260	    //         local_score[total_boxes] = score;
261	    //         total_boxes++;
262	    //     }
263	    // } // class
264	
265	    // if (total_boxes & 1)  // if odd
266	    //     total_boxes--;    // drop last bo    
267	
268	    // WRITE_BACK_X: // temp debug
269	    // for (int i = 0; i < total_boxes; i++) {
