    // }

    // WRITE_BACK_H: // temp debug
    // for (int i = 0; i < total_boxes; i++) {
    //     out_boxes_h[i] = local_boxes_h[i];
    // }

    // WRITE_BACK_CLS: // temp debug
    // for (int i = 0; i < total_boxes; i++) {
    //     out_cls[i] = local_cls[i];
    // }

    // WRITE_BACK_SCORE: // temp debug
    // for (int i = 0; i < total_boxes; i++) {
    //     out_score[i] = local_score[i];
    // }

    // out_box_num = total_boxes; // temp debug
    // return; // temp debug
    } // anchor loop

    if (total_boxes & 1)  // if odd
        total_boxes--;    // drop last box    

    WRITE_BACK_X: // temp debug
    for (int i = 0; i < total_boxes; i++) {
        out_boxes_x[i] = local_boxes_x[i];
    }

    WRITE_BACK_Y: // temp debug
    for (int i = 0; i < total_boxes; i++) {
