#pragma once
#include <iomanip>
#include <iostream>
#include <opencv2/core.hpp>
#include <opencv2/highgui.hpp>
#include <opencv2/imgproc.hpp>

DEF_ENV_PARAM(PROCESS_RESULTS_DEBUG, "0");


static cv::Scalar getColor(int label) {
  return cv::Scalar(label * 2, 255 - label * 2, label + 50);
}

static cv::Mat process_result(cv::Mat& image,
                              const vitis::ai::YOLOv8Result& result,
                              bool is_jpeg) {
  for (const auto& result : result.bboxes) {
    int label = result.label;
    auto& box = result.box;
    LOG_IF(INFO, ENV_PARAM(PROCESS_RESULTS_DEBUG)) << "RESULT: " << label << "\t" << std::fixed
                          << std::setprecision(2) << box[0] << "\t" << box[1]
                          << "\t" << box[2] << "\t" << box[3] << "\t"
                          << std::setprecision(6) << result.score << "\n";

    cv::rectangle(image, cv::Point(box[0], box[1]), cv::Point(box[0]+box[2], box[1]+box[3]),
                  getColor(label), 1, 1, 0);
  }
  return image;
}

void process_results_txt(const vitis::ai::YOLOv8Result& result,
                         std::vector<std::string>& all_results, 
                         const std::string& file_name) {

    for (const auto& result : result.bboxes) {
        std::string result_string = file_name + ",";
        result_string += std::to_string(result.box[0]) + ",";
        result_string += std::to_string(result.box[1]) + ",";
        result_string += std::to_string(result.box[2]) + ",";
        result_string += std::to_string(result.box[3]) + ",";
        result_string += std::to_string(result.label) + ",";
        result_string += std::to_string(result.score);
        all_results.push_back(result_string);
    }
}

