#include <glog/logging.h>

#include <fstream>
#include <iomanip>
#include <iostream>
#include <memory>
#include <opencv2/core.hpp>
#include <opencv2/highgui.hpp>
#include <opencv2/imgproc.hpp>
#include <vector>
#include <vitis/ai/demo_accuracy.hpp>
#include <vitis/ai/nnpp/yolov8.hpp>
#include <vitis/ai/yolov8.hpp>
#include <vitis/ai/bounded_queue.hpp>
#include <vitis/ai/env_config.hpp>
extern int g_last_frame_id;

std::string model_name;
bool is_first = true;
using namespace std;
namespace vitis {
namespace ai {

using queue_t = vitis::ai::BoundedQueue<FrameInfo>;
using queue_dpu = vitis::ai::BoundedQueue<DpuResultInfo>;

std::string remove_tif_extension(const std::string& filename) {
    size_t pos = filename.rfind(".tif");
    return (pos != std::string::npos) ? filename.substr(0, pos) : filename;
}

struct YolovXAcc : public AccThread {
  YolovXAcc(std::string output_file)
      : AccThread(), of(output_file, std::ofstream::out) {
    dpu_result.frame_id = -1;
  }

  virtual ~YolovXAcc() { of.close(); }

  static std::shared_ptr<YolovXAcc> instance(std::string output_file) {
    static std::weak_ptr<YolovXAcc> the_instance;
    std::shared_ptr<YolovXAcc> ret;
    if (the_instance.expired()) {
      ret = std::make_shared<YolovXAcc>(output_file);
      the_instance = ret;
    }
    ret = the_instance.lock();
    assert(ret != nullptr);
    return ret;
  }

  void process_result(DpuResultInfo dpu_result) {
    auto result = (YOLOv8Result*)dpu_result.result_ptr.get();
    for (const auto& bbox : result->bboxes) {

      of << fixed << setprecision(0)
         << "{\"chip_id\": \"" << remove_tif_extension(dpu_result.single_name)
         << "\", \"label\": " << bbox.label << ", \"x\": "
         << fixed << setprecision(6) << bbox.box[0] << ", \"y\": " << bbox.box[1] << ", \"w\": "
         << bbox.box[2] << ", \"h\": " << bbox.box[3] << ", \"score\": " << bbox.score
         << "}," << endl;
    }
  }

  virtual int run() override {
    if (is_first) {
      of << "[" << endl;
      is_first = false;
    }
    if (g_last_frame_id == int(dpu_result.frame_id)) {
      of.seekp(-2L, ios::end);
      of << endl << "]" << endl;
      exit(0);
    }
    if (queue_->pop(dpu_result, std::chrono::milliseconds(50000))) {
      process_result(dpu_result);
    }
    return 0;
  }

  DpuResultInfo dpu_result;
  std::ofstream of;
};

struct TiffReadImagesThread : public vitis::ai::ReadImagesThread {
  // Inherit constructor from base class
  using vitis::ai::ReadImagesThread::ReadImagesThread;

  virtual int run() override {
    std::ifstream fs(images_list_file_);
    std::string line;
    std::string single_name;
    while (getline(fs, line)) {
      auto image = cv::imread(line, cv::IMREAD_UNCHANGED);
      if (image.empty()) {
        std::cerr << "cannot read image: " << line;
        continue;
      }
      single_name = get_single_name(line);
      int w = image.cols;
      int h = image.rows;
      auto frame = vitis::ai::FrameInfo{++frame_id_, std::move(image), single_name, w, h};
      while (!queue_->push(frame, std::chrono::milliseconds(500))) {
        if (is_stopped()) {
          return -1;
        }
      }
      LOG_IF(INFO, ENV_PARAM(DEBUG_DEMO))
          << "push image frame_id " << frame_id_ << ",read images queue size "
          << queue_->size();
    }
    g_last_frame_id = frame_id_;
    return -1;
  }
};

template <typename FactoryMethod>
int xview3_benchmark(
    int argc, char* argv[], const FactoryMethod& factory_method,
    std::shared_ptr<vitis::ai::AccThread> acc_thread, int start_pos = 1,
    std::shared_ptr<TiffReadImagesThread> read_thread = NULL) {
  signal(SIGINT, vitis::ai::MyThread::signal_handler);
  parse_opt(argc, argv, start_pos);
  {
    auto images_queue = std::unique_ptr<queue_t>{new queue_t{50}};
    if (read_thread == NULL) {
      read_thread = std::shared_ptr<TiffReadImagesThread>(
          new TiffReadImagesThread{g_input_file, images_queue.get()});
    } else {
      read_thread->set_filename_and_queue(g_input_file, images_queue.get());
    }
    auto dpu_run_thread = std::vector<std::unique_ptr<vitis::ai::DpuRunThread>>{};
    auto sorting_queue =
        std::unique_ptr<queue_dpu>(new queue_dpu(500 * g_num_of_threads));
    auto acc_queue = acc_thread->getQueue();
    for (int i = 0; i < g_num_of_threads; ++i) {
      dpu_run_thread.emplace_back(new vitis::ai::DpuRunThread(
          vitis::ai::create_rundpu_filter(factory_method), images_queue.get(),
          sorting_queue.get(), std::to_string(i)));
    }
    auto sorting_thread = std::unique_ptr<vitis::ai::SortDpuThread>(
        new vitis::ai::SortDpuThread(sorting_queue.get(), acc_queue, std::to_string(0)));
    // start everything
    MyThread::start_all();
    acc_thread->wait();
    MyThread::stop_all();
    MyThread::wait_all();
  }
  return 0;
}

} // namespace ai
}  // namespace vitis


int main(int argc, char* argv[]) {
  model_name = argv[1];
  return xview3_benchmark(
      argc, argv,
      [&] { return vitis::ai::YOLOv8::create(model_name, false); },
      vitis::ai::YolovXAcc::instance(argv[3]), 2);
}

